/**
 * Scraper Rate Limiter Service
 * Implements per-source rate limiting for scraper requests
 * Integrates with error recovery and respects source-specific rate limits
 */

import { logger } from './loggerService';
import { createAppError } from '../middleware/errorHandler';
import { ErrorCode } from '../constants/errorCodes';
import { errorRecoveryService } from './errorRecoveryService';

/**
 * Rate limit entry for tracking requests
 */
interface RateLimitEntry {
  requests: number[];
  lastRequest: number;
}

/**
 * Rate limit configuration
 */
export interface ScraperRateLimitConfig {
  requestsPerMinute: number;
  burstLimit?: number; // Maximum requests in burst
  minDelay?: number; // Minimum delay between requests (ms)
}

/**
 * Scraper Rate Limiter Service
 */
export class ScraperRateLimiter {
  private rateLimits: Map<string, RateLimitEntry> = new Map();
  private cleanupInterval: NodeJS.Timeout;

  constructor() {
    // Cleanup old entries every 5 minutes
    this.cleanupInterval = setInterval(() => {
      this.cleanup();
    }, 300000);
  }

  /**
   * Check if request can proceed for a source
   */
  async checkRateLimit(
    sourceId: string,
    config: ScraperRateLimitConfig
  ): Promise<void> {
    const now = Date.now();
    const entry = this.rateLimits.get(sourceId);

    // Initialize entry if not exists
    if (!entry) {
      this.rateLimits.set(sourceId, {
        requests: [now],
        lastRequest: now,
      });
      return;
    }

    // Clean up requests older than 1 minute
    const oneMinuteAgo = now - 60000;
    entry.requests = entry.requests.filter(time => time > oneMinuteAgo);

    // Check minimum delay between requests
    const minDelay = config.minDelay || 0;
    const timeSinceLastRequest = now - entry.lastRequest;

    if (timeSinceLastRequest < minDelay) {
      const waitTime = minDelay - timeSinceLastRequest;
      
      logger.debug('Enforcing minimum delay between scraper requests', {
        sourceId,
        minDelay,
        timeSinceLastRequest,
        waitTime,
      });

      await this.sleep(waitTime);
    }

    // Check burst limit
    const burstLimit = config.burstLimit || config.requestsPerMinute;
    if (entry.requests.length >= burstLimit) {
      const oldestRequest = entry.requests[0];
      const waitTime = 60000 - (now - oldestRequest);

      if (waitTime > 0) {
        logger.warn('Scraper rate limit exceeded, waiting', {
          sourceId,
          requestsPerMinute: config.requestsPerMinute,
          currentRequests: entry.requests.length,
          waitTime,
        });

        // Throw rate limit error that can be caught by error recovery
        throw createAppError(
          `Rate limit exceeded for scraper source. Wait ${Math.ceil(waitTime / 1000)}s`,
          ErrorCode.SCRAPER_RATE_LIMITED,
          429,
          { 
            sourceId, 
            retryAfter: Math.ceil(waitTime / 1000),
            requestsPerMinute: config.requestsPerMinute,
            currentRequests: entry.requests.length,
          }
        );
      }
    }

    // Check requests per minute limit
    if (entry.requests.length >= config.requestsPerMinute) {
      const oldestRequest = entry.requests[0];
      const waitTime = 60000 - (now - oldestRequest);

      if (waitTime > 0) {
        logger.warn('Scraper rate limit exceeded, waiting', {
          sourceId,
          requestsPerMinute: config.requestsPerMinute,
          currentRequests: entry.requests.length,
          waitTime,
        });

        // Throw rate limit error
        throw createAppError(
          `Rate limit exceeded for scraper source. Wait ${Math.ceil(waitTime / 1000)}s`,
          ErrorCode.SCRAPER_RATE_LIMITED,
          429,
          { 
            sourceId, 
            retryAfter: Math.ceil(waitTime / 1000),
            requestsPerMinute: config.requestsPerMinute,
            currentRequests: entry.requests.length,
          }
        );
      }
    }

    // Record this request
    entry.requests.push(now);
    entry.lastRequest = now;

    logger.debug('Scraper rate limit check passed', {
      sourceId,
      requestsInLastMinute: entry.requests.length,
      limit: config.requestsPerMinute,
    });
  }

  /**
   * Execute scraper request with rate limiting
   */
  async executeWithRateLimit<T>(
    sourceId: string,
    config: ScraperRateLimitConfig,
    operation: () => Promise<T>
  ): Promise<T> {
    try {
      // Check rate limit before executing
      await this.checkRateLimit(sourceId, config);

      // Execute the operation
      const result = await operation();

      return result;
    } catch (error) {
      // If it's a rate limit error, log and rethrow
      if ((error as any)?.errorCode === ErrorCode.SCRAPER_RATE_LIMITED) {
        logger.warn('Scraper request rate limited', {
          sourceId,
          error: error instanceof Error ? error.message : String(error),
        });
      }

      throw error;
    }
  }

  /**
   * Execute scraper request with rate limiting and error recovery
   */
  async executeWithRateLimitAndRecovery<T>(
    sourceId: string,
    config: ScraperRateLimitConfig,
    operation: () => Promise<T>,
    options?: {
      maxRetries?: number;
      onRetry?: (error: any, attempt: number, delay: number) => void;
    }
  ): Promise<T> {
    return errorRecoveryService.executeWithRetry(
      async () => {
        // Check rate limit before each attempt
        await this.checkRateLimit(sourceId, config);
        
        // Execute the operation
        return await operation();
      },
      {
        operationName: `scraper-request-${sourceId}`,
        retryConfig: {
          maxRetries: options?.maxRetries || 3,
          initialDelay: 2000,
          maxDelay: 60000,
          backoffMultiplier: 2,
          jitterFactor: 0.1,
        },
        onRetry: options?.onRetry,
        shouldRetry: (error, attempt) => {
          // Classify the error
          const classification = errorRecoveryService.classifyError(error);
          
          // For rate limit errors, always retry with longer delay
          if (classification.type === 'RATE_LIMIT') {
            return true;
          }

          // For other errors, use default retry logic
          return classification.isRetryable && attempt <= classification.maxRetries;
        },
      }
    );
  }

  /**
   * Get rate limit status for a source
   */
  getRateLimitStatus(
    sourceId: string,
    config: ScraperRateLimitConfig
  ): {
    requestsInLastMinute: number;
    limit: number;
    remaining: number;
    resetTime: number;
    isLimited: boolean;
  } {
    const now = Date.now();
    const entry = this.rateLimits.get(sourceId);

    if (!entry) {
      return {
        requestsInLastMinute: 0,
        limit: config.requestsPerMinute,
        remaining: config.requestsPerMinute,
        resetTime: now + 60000,
        isLimited: false,
      };
    }

    // Clean up old requests
    const oneMinuteAgo = now - 60000;
    const recentRequests = entry.requests.filter(time => time > oneMinuteAgo);
    const remaining = Math.max(0, config.requestsPerMinute - recentRequests.length);
    const oldestRequest = recentRequests[0] || now;
    const resetTime = oldestRequest + 60000;

    return {
      requestsInLastMinute: recentRequests.length,
      limit: config.requestsPerMinute,
      remaining,
      resetTime,
      isLimited: recentRequests.length >= config.requestsPerMinute,
    };
  }

  /**
   * Reset rate limit for a source
   */
  resetRateLimit(sourceId: string): void {
    this.rateLimits.delete(sourceId);
    logger.info('Scraper rate limit reset', { sourceId });
  }

  /**
   * Get all rate limit statuses
   */
  getAllRateLimitStatuses(): Record<string, {
    requestsInLastMinute: number;
    lastRequest: number;
  }> {
    const now = Date.now();
    const oneMinuteAgo = now - 60000;
    const statuses: Record<string, any> = {};

    for (const [sourceId, entry] of this.rateLimits.entries()) {
      const recentRequests = entry.requests.filter(time => time > oneMinuteAgo);
      statuses[sourceId] = {
        requestsInLastMinute: recentRequests.length,
        lastRequest: entry.lastRequest,
      };
    }

    return statuses;
  }

  /**
   * Calculate optimal delay for next request
   */
  calculateOptimalDelay(
    sourceId: string,
    config: ScraperRateLimitConfig
  ): number {
    const entry = this.rateLimits.get(sourceId);

    if (!entry) {
      return 0;
    }

    const now = Date.now();
    const oneMinuteAgo = now - 60000;
    const recentRequests = entry.requests.filter(time => time > oneMinuteAgo);

    // If we're at the limit, calculate delay until oldest request expires
    if (recentRequests.length >= config.requestsPerMinute) {
      const oldestRequest = recentRequests[0];
      const delay = Math.max(0, 60000 - (now - oldestRequest));
      return delay;
    }

    // Check minimum delay
    const minDelay = config.minDelay || 0;
    const timeSinceLastRequest = now - entry.lastRequest;

    if (timeSinceLastRequest < minDelay) {
      return minDelay - timeSinceLastRequest;
    }

    return 0;
  }

  /**
   * Wait for rate limit to allow request
   */
  async waitForRateLimit(
    sourceId: string,
    config: ScraperRateLimitConfig
  ): Promise<void> {
    const delay = this.calculateOptimalDelay(sourceId, config);

    if (delay > 0) {
      logger.info('Waiting for rate limit', {
        sourceId,
        delay,
        requestsPerMinute: config.requestsPerMinute,
      });

      await this.sleep(delay);
    }
  }

  /**
   * Cleanup old entries
   */
  private cleanup(): void {
    const now = Date.now();
    const fiveMinutesAgo = now - 300000;
    const keysToDelete: string[] = [];

    for (const [sourceId, entry] of this.rateLimits.entries()) {
      // Remove entries with no recent requests
      if (entry.lastRequest < fiveMinutesAgo) {
        keysToDelete.push(sourceId);
      } else {
        // Clean up old request timestamps
        const oneMinuteAgo = now - 60000;
        entry.requests = entry.requests.filter(time => time > oneMinuteAgo);
      }
    }

    keysToDelete.forEach(key => this.rateLimits.delete(key));

    if (keysToDelete.length > 0) {
      logger.debug('Scraper rate limiter cleanup', {
        entriesRemoved: keysToDelete.length,
        remainingEntries: this.rateLimits.size,
      });
    }
  }

  /**
   * Sleep utility
   */
  private sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
  }

  /**
   * Destroy rate limiter and cleanup
   */
  destroy(): void {
    clearInterval(this.cleanupInterval);
    this.rateLimits.clear();
    logger.info('Scraper rate limiter destroyed');
  }
}

